7	export function isOverThreeLines(text, fontSize, containerWidth) {
8	  // 创建一个隐藏的DOM元素来测量
9	  const measureElement = document.createElement('div')
10	  measureElement.style.position = 'absolute'
11	  measureElement.style.whiteSpace = 'pre-wrap' // 保留空格和换行
12	  measureElement.style.wordWrap = 'break-word' // 让长单词也能换行
13	  measureElement.style.visibility = 'hidden' // 隐藏元素
14	  measureElement.style.fontSize = `${fontSize}px` // 设置字号
15	  measureElement.style.width = `${containerWidth}px` // 设置容器宽度
16	  measureElement.textContent = text // 放入待测文本
17	  document.body.appendChild(measureElement) // 将测量元素加入到DOM
18	
19	  // 计算行数
20	  const lineCount = measureElement.scrollHeight / measureElement.offsetHeight
21	
22	  document.body.removeChild(measureElement) // 测量完移除元素
23	
24	  return lineCount > 3 // 返回是否超过三行
25	}
