92	export function getMatchedUserOrgId(
93	  data: OrgNode[],
94	  userInfo?: Partial<CurrentUserInfo>,
95	) {
96	  const targetOrgIds = [userInfo?.belongDeptId, userInfo?.belongEntityId]
97	    .filter(Boolean)
98	    .map((item) => String(item))
99	
100	  if (_.isEmpty(targetOrgIds)) {
101	    return undefined
102	  }
103	
104	  const findOrgId = (nodes?: OrgNode[]): string | undefined => {
105	    if (!Array.isArray(nodes)) {
106	      return undefined
107	    }
108	
109	    for (const node of nodes) {
110	      if (targetOrgIds.includes(String(node.orgId))) {
111	        return String(node.orgId)
112	      }
113	
114	      const childMatchedOrgId = findOrgId(node.children)
115	      if (childMatchedOrgId) {
116	        return childMatchedOrgId
117	      }
118	    }
119	
120	    return undefined
121	  }
122	
123	  return findOrgId(data)
124	}
