238	/**
239	 * 根据 riskName 过滤 riskDetailActivityBOList 数据
240	 * @param {Array} dataList - 原始数据列表
241	 * @param {string} riskName - 要过滤的 riskName
242	 * @returns {Array} 过滤后的数据列表
243	 */
244	export const filterByRiskId = (dataList, riskName) => {
245	  if (!Array.isArray(dataList) || !riskName) {
246	    return []
247	  }
248	
249	  return dataList
250	    .filter((activity) => {
251	      // 检查 recordRiskDetailBOList 中是否包含指定的 riskId
252	      const hasRiskInDetails = activity.recordRiskDetailBOList?.some(
253	        (risk) => risk.nameAr === riskName || risk.name === riskName,
254	      )
255	
256	      // 检查 recordRiskProceduresBOList 中是否包含指定的 riskId
257	      const hasRiskInProcedures = activity.recordRiskProceduresBOList?.some(
258	        (procedure) =>
259	          procedure.riskNameAr === riskName || procedure.riskName === riskName,
260	      )
261	
262	      return hasRiskInDetails || hasRiskInProcedures
263	    })
264	    .map((activity) => {
265	      // 创建深拷贝以避免修改原数据
266	      const filteredActivity = { ...activity }
267	
268	      // 过滤 recordRiskDetailBOList
269	      if (filteredActivity.recordRiskDetailBOList) {
270	        filteredActivity.recordRiskDetailBOList =
271	          filteredActivity.recordRiskDetailBOList.filter(
272	            (risk) => risk.nameAr === riskName || risk.name === riskName,
273	          )
274	      }
275	
276	      // 过滤 recordRiskProceduresBOList
277	      if (filteredActivity.recordRiskProceduresBOList) {
278	        filteredActivity.recordRiskProceduresBOList =
279	          filteredActivity.recordRiskProceduresBOList.filter(
280	            (procedure) =>
281	              procedure.riskNameAr === riskName ||
282	              procedure.riskName === riskName,
283	          )
284	      }
285	
286	      return filteredActivity
287	    })
288	}
